+            normalize: true,
+            max_length: 256,
+            batch_size: 32,
+            num_threads: num_cpus::get(),
+            execution_provider: ExecutionProvider::default(),
+            cache_dir: default_cache_dir(),
+            show_progress: true,
+            use_fp16: false,
+            optimize_graph: true,
