+
+        let dimension = query.len();
+        let num_candidates = candidates.len();
+
+        // Flatten candidates into contiguous buffer
+        let candidates_flat: Vec<f32> = candidates.iter().flat_map(|c| c.iter().copied()).collect();
+
+        // Create buffers
