+        // Cleanup
+        backend.release_buffer(buf_a)?;
+        backend.release_buffer(buf_b)?;
+        backend.release_buffer(output_buf)?;
+        backend.release_buffer(params_buf)?;
+        backend.release_pipeline(pipeline)?;
+
