+/// Shader registry for managing compute shaders
+#[derive(Debug)]
+pub struct ShaderRegistry {
+    shaders: HashMap<String, ShaderModule>,
+}
+
+/// Shader module information
+#[derive(Debug, Clone)]
+pub struct ShaderModule {
+    /// Shader name
+    pub name: String,
+    /// WGSL source code
+    pub source: String,
